import { ArrowLink } from "@/components/common/ArrowLink";
import { Button } from "@/components/common/Button";
import { Reveal } from "@/components/common/Reveal";
import { solutions } from "@/constants/content";

const solutionTags: Record<string, string> = {
  "Loan Origination System": "NBFC",
  "Loan Management System": "NBFC"
};

export function SolutionsSection() {
  return (
    <section className="section-dark relative overflow-hidden py-24 md:py-32" id="solutions">
      <div className="mx-auto grid max-w-[1440px] gap-16 px-5 sm:px-8 md:grid-cols-[0.68fr_1fr] md:px-20">
        <Reveal className="md:sticky md:top-32 md:h-fit">
          <h2 className="max-w-[500px] text-3xl font-semibold leading-tight text-[color:var(--section-ink)] md:text-[40px]">
            <span className="lg:whitespace-nowrap">All of our solutions are</span>{" "}
            <span>tailor-made to your needs</span>
          </h2>
          <Button className="mt-9" href="#contact" variant="outline">
            REQUEST DEMO
          </Button>
        </Reveal>

        <div className="grid gap-x-16 gap-y-14 sm:grid-cols-2">
          {solutions.map((solution, index) => (
            <Reveal
              as="article"
              className="group relative rounded-[8px] p-1 transition duration-300 hover:-translate-y-1 hover:bg-accent/10"
              delay={index * 0.05}
              key={solution.title}
            >
              <div className="relative h-full rounded-[7px] border border-transparent p-4 transition duration-300 group-hover:border-accent/20 group-hover:bg-[color:var(--surface-elevated)]">
                <div className="flex items-center justify-between gap-4">
                  <SolutionMark title={solution.title} />
                  {solutionTags[solution.title] ? (
                    <span className="rounded-full border border-accent/30 px-3 py-1 text-xs font-semibold text-accent">
                      {solutionTags[solution.title]}
                    </span>
                  ) : null}
                </div>
                <h3 className="mt-6 text-lg font-semibold text-[color:var(--section-ink)]">
                  {solution.title}
                </h3>
                <p className="mt-4 max-w-[330px] text-sm leading-6 text-[color:var(--muted)]">
                  {solution.body}
                </p>
                <ArrowLink className="mt-5" href="#contact">
                  LEARN MORE
                </ArrowLink>
              </div>
            </Reveal>
          ))}
        </div>
      </div>
    </section>
  );
}

